window.__QUIZ_DATA__=[{"id":"objective>Physics>2016>1","subject":"Physics","year":"2016","type":"Objective","topic":"DERIVED QUANTITIES AND DIMENSIONAL ANALYSIS :","question":"The dimensions of momentum are","images":[],"options":{"A":"MLT","B":"ML-1T-1","C":"MLT-1","D":"ML-1T"},"answer":"C","explanation":"The dimension of momentum is given by the product of mass and velocity. The dimension of mass is M (mass), the dimension of velocity is LT-1 (length per time). Therefore, the dimension of momentum is MLT-1.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2016>2","subject":"Physics","year":"2016","type":"Objective","topic":"FLUID AT REST : VOLUME, DENSITY AND RELATIVE DENSITY","question":"A student measures the volume of a liquid using a measuring cylinder. What else needs to be measured by the student in order to determine the density of the liquid?","images":[],"options":{"A":"Depth of the liquid in the cylinder","B":"Mass of the cylinder","C":"Mass of the liquid","D":"Temperature of the liquid"},"answer":"C","explanation":"The mass of the liquid is also required to determine the density of the liquid since,  Density=massvolume","marks":"1","difficulty":"1"},{"id":"objective>Physics>2016>3","subject":"Physics","year":"2016","type":"Objective","topic":"HOOKE\u2019S LAW, YOUNG\u2019S MODULES AND WORK DONE IN SPRINGS AND STRING :","question":"The diagram above represents the graph of stress against strain for an elastic wire. The point Q on the graph is the","images":["data:image/png;base64,"],"options":{"A":"elastic limit","B":"breaking point","C":"yield point","D":"proportional limit"},"answer":"B","explanation":"The point Q on the graph is the is the breaking point.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>4","subject":"Physics","year":"2016","type":"Objective","topic":"MOTION : MOTION UNDER GRAVITY","question":"A ball is dropped from the top of a tower. Due to air resistance, it reaches terminal velocity. Which of the following statement(s) about its motion is/are correct?  I. The acceleration of the ball is zero  II. The net force on the ball is zero  III. The velocity of the ball increases","images":[],"options":{"A":"I only","B":"I and II only","C":"II and III only","D":"I, II and III"},"answer":"B","explanation":"The acceleration of the ball is zero due to the fact that it is due to air resistance and gravity. The net force on the ball is also zero because it is the same amount of force that it applied on both sides of the ball.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2016>5","subject":"Physics","year":"2016","type":"Objective","topic":"FLUID AT REST : PRESSURE IN FLUIDS","question":"Which of the following substances lowers the surface tension of water?","images":[],"options":{"A":"Metal","B":"Sand","C":"Detergent","D":"Paper"},"answer":"C","explanation":"Surface tension is the property of a liquid that allows it to resist an external force. It is caused by the cohesive forces between liquid molecules. Detergents lower the surface tension of water by disrupting the cohesive forces between water molecules. This is why detergent is often added to water when washing dishes or clothes, as it allows the water to more effectively penetrate and clean the items.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>6","subject":"Physics","year":"2016","type":"Objective","topic":"EQUILIBRIUM OF FORCES : PRINCIPLE OF MOMENTS","question":"An object of volume 400cm3 and density 2.5gcm-3 is suspended  from a spring balance with half its volume immersed in water. Determine the reading on the spring balance.  (Density of water = 1 gcm-3)","images":[],"options":{"A":"1200g","B":"1000g","C":"800g","D":"400g"},"answer":"C","explanation":"Recall, Density = m/v  2.5 = m \u00f7 400  m = 2.5/400  m = 1000g  Also, mass of object in water = Density of water \u00d7 Half Volume of water  m = 1gcm-3 \u00d7 200cm3  m = 200g  \u2234 Spring Balance Reading = (1000 - 200)g    = 800g","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>7","subject":"Physics","year":"2016","type":"Objective","topic":"WORK, ENERGY AND POWER : CONCEPT OF WORK","question":"The diagram above illustrates a force-distance graph for the motion of a wooden block. Determine the work done on the block when moved through a distance of 5m.","images":["data:image/png;base64,"],"options":{"A":"4J","B":"15J","C":"25J","D":"100J"},"answer":"D","explanation":"Recall, Workdone = Force \u00d7 distance   where, F = 20N, d = 5m  Workdone = 20 \u00d7 5 = 100Nm  \u2234 Workdone = 100J","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>8","subject":"Physics","year":"2016","type":"Objective","topic":"RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION","question":"The two positions of a body undergoing a uniformly accelerated motion are (10s, 10ms-1) and (30s, 50ms-1) on the velocity-time graph. Calculate the magnitude of the acceleration of the body.","images":[],"options":{"A":"0.5ms-2","B":"2.0ms-2","C":"10.0ms-2","D":"40.0ms2"},"answer":"B","explanation":"(10s, 10ms-1) and (30s, 50ms1)  Acceleration=\u0394vt  Acceleration=50 - 1030 - 10=4020=2ms-2","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>9","subject":"Physics","year":"2016","type":"Objective","topic":"PROJECTILE MOTION :","question":"At a birthday party, the celebrant pops a corked fruit wine. If the cork shoots out of the bottle at an angle of 40\u00b0 to the horizontal and travels a horizontal distance of 4.5 m in 1.25s, calculate the initial speed of the cork","images":[],"options":{"A":"4.2 ms-1","B":"4.7 ms-1","C":"5.6 ms-1","D":"7.1 ms-1"},"answer":"B","explanation":"Given; \u03b8 = 40\u00b0, R = 4.50m, t = 1.25s, u = ?  Recall, R = ucos\u03b8t  4.50 = u cos40\u00b0 \u00d7 1.25  u=4.50.766 \u00d7 1.25=4.50.96  u = 4.7ms-1","marks":"1","difficulty":"3"},{"id":"objective>Physics>2016>10","subject":"Physics","year":"2016","type":"Objective","topic":"EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES","question":"A uniform metre rule is balanced on a fulcrum placed at the 35cm mark by suspending a mass of 120g at the 10cm mark. Calculate the mass of the metre rule","images":[],"options":{"A":"60g","B":"80g","C":"120g","D":"200g"},"answer":"D","explanation":"Clockwise moment = anticlockwise moment half of a meter rule  = 50cm which Is the mid-point   (35-10) x 120 = 50 \u2013 35 x W  25 x 120 = 15W  W = 200g","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>11","subject":"Physics","year":"2016","type":"Objective","topic":"MOTION : TYPES OF FORCE","question":"A plank is placed along the path on which a wheel barrow containing sand is pushed at a construction site to prevent it from sticking as illustrated in the diagram above. The large area of the plank prevents the wheel barrow from getting stuck by","images":["data:image/png;base64,"],"options":{"A":"increasing the reaction on the ground","B":"increasing the pressure on the ground","C":"decreasing the pressure on the ground","D":"decreasing the weight on the ground"},"answer":"B","explanation":"The plank prevents the barrow from getting stuck because it increases the pressure on the ground.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>12","subject":"Physics","year":"2016","type":"Objective","topic":"MOTION : SIMPLE IDEAS OF CIRCULAR MOTION","question":"When a body is thrown vertically upwards, its velocity at the maximum height is","images":[],"options":{"A":"maximum","B":"zero","C":"double its initial value","D":"half its initial value"},"answer":"B","explanation":"The velocity of a body at its maximum height is zero (0) because the body rests briefly before falling.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>13","subject":"Physics","year":"2016","type":"Objective","topic":"SOUND WAVES : RESONANCE","question":"Resonance occurs when one vibrating object causes a second object to vibrate at its own natural","images":[],"options":{"A":"amplitude","B":"speed","C":"frequency","D":"intensity"},"answer":"C","explanation":"Resonance occurs when one vibrating object causes a second object to vibrate at its own natural frequency. This is because resonance is a phenomenon that occurs when the frequency of a force applied to a system matches the natural frequency of vibration of the system, resulting in a large amplitude of vibration.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>14","subject":"Physics","year":"2016","type":"Objective","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"The mouth piece of a telephone handset converts","images":[],"options":{"A":"electrical energy to sound energy","B":"sound energy to electrical energy","C":"sound energy to radiowave","D":"radiowave to sound energy"},"answer":"B","explanation":"The mouthpiece of a telephone handset converts sound energy to electrical energy. This is because when you speak into the mouthpiece of a telephone, your voice causes the air molecules inside it to vibrate. These vibrations are then converted into electrical signals by a microphone in the mouthpiece. These electrical signals can then be transmitted over telephone lines to another telephone, where they are converted back into sound.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>15","subject":"Physics","year":"2016","type":"Objective","topic":"MOTION : CAUSE OF MOTION","question":"Four identical trolleys are loaded with different masses and move along a straight road at the same speed. Which of the trolleys has the greatest inertia?","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"D","explanation":"The trolley carrying the highest mass/load will have the greatest Inertia because Inertia is the reluctance of a body.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2016>16","subject":"Physics","year":"2016","type":"Objective","topic":"HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT","question":"In the clinical thermometer, the function of the kink is to   I. prevent the back flow of mercury after use  II. ensure the back flow of mercury after use  III. maintain the thermometric property of mercury  IV. allow the temperature attained to be read","images":[],"options":{"A":"I only","B":"I and II only","C":"I and IV only","D":"III and IV only"},"answer":"C","explanation":"The kink in a clinical thermometer helps to prevent backflow of the mercury after use which also simultaneously allows any temperature attained to be read.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>17","subject":"Physics","year":"2016","type":"Objective","topic":"HEAT ENERGY : BOILING POINT","question":"Which of the following statements correctly defines the boiling point of a liquid. The temperature at which the","images":[],"options":{"A":"saturated vapour pressure equals the atmospheric pressure","B":"molecules leave the liquid at a rate equal to the rate at which they return","C":"molecules leave the liquid at a rate higher than that at which they return","D":"molecules leave the liquid at a rate lower than the rate at which they return"},"answer":"A","explanation":"The boiling point of a liquid is the point at which the saturated vapour pressure is equal to the atmospheric/earth pressure.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>18","subject":"Physics","year":"2016","type":"Objective","topic":"HEAT ENERGY : HUMIDITY AND THE WEATHER","question":"The diagram above is used to determine the","images":["data:image/png;base64,"],"options":{"A":"boiling point of water","B":"atmospheric pressure","C":"upper fixed point of a thermometer","D":"amount of water in the atmosphere"},"answer":"C","explanation":"The diagram above which is a Hypsometer is used to determine the upper fixed point of a thermometer.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>19","subject":"Physics","year":"2016","type":"Objective","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"An aluminium rod of length 1.8 m at 10\u00b0C is heated to produce a difference in length of 0.007m. Calculate the temperature to which it is heated.  (Linear expansivity of aluminium = 2.3 \u00d7 10-5K-1)","images":[],"options":{"A":"155\u00b0C","B":"160\u00b0C","C":"169\u00b0C","D":"179\u00b0C"},"answer":"D","explanation":"Recall,LinearExpansivity,\u03b1=l2 - l1l1\u0394\u03b8  =l2 - l1l1(\u03b82 - \u03b81)  2.3\u00d710-5=0.0071.8 \u00d7 (\u03b81-10)  0.007 = 2.3 \u00d7 10-5 \u00d7 1.8 \u00d7 (\u03b81 - 10)  \u03b81-10=0.0072.3 \u00d7 10-5 \u00d7 1.8  \u03b81 = 179\u00b0C","marks":"1","difficulty":"3"},{"id":"objective>Physics>2016>20","subject":"Physics","year":"2016","type":"Objective","topic":"HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT","question":"A mercury-in-glass thermometer reads 4cm at ice point and 29cm at steam point. Calculate the temperature when the mercury level is at 9cm.","images":[],"options":{"A":"13\u00b0C","B":"20\u00b0C","C":"33\u00b0C","D":"38\u00b0C"},"answer":"B","explanation":"9 - 429 - 4=\u03b1100  500 = 25\u03b1  \u03b1=50025  \u03b1 = 20\u00b0C","marks":"1","difficulty":"3"},{"id":"objective>Physics>2016>21","subject":"Physics","year":"2016","type":"Objective","topic":"HEAT ENERGY : EFFECTS OF HEAT ON MATTER","question":"The continuous stirring in the method of mixtures to determine the specific thermal capacity of a substance ensures","images":[],"options":{"A":"continuous dissipation of heat of the room","B":"uniform distribution of thermal energy to all parts of the mixture","C":"that thermal energy is confined to the mixture","D":"that there is rapid heat exchange"},"answer":"B","explanation":"Continuous stirring in the method of mixtures ensures uniform distribution of thermal energy to all parts of the mixture. This is because stirring helps to distribute the heat evenly throughout the mixture, ensuring that all parts of the mixture reach the same temperature.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>22","subject":"Physics","year":"2016","type":"Objective","topic":"HEAT ENERGY : EFFECTS OF HEAT ON MATTER","question":"Which of the following statements is correct about the effect of dissolved salt on the freezing point of water?","images":[],"options":{"A":"The freezing point is lowered","B":"The freezing point is increased","C":"There is no change in the freezing point","D":"The change in the freezing point depends on the temperature of the surrounding"},"answer":"A","explanation":"When salt is dissolved in water, it lowers the freezing point of the water. This is a process known as freezing point depression. The salt interferes with the intermolecular attractions between the water molecules, reducing their ability to form the crystalline structure necessary for ice to form and thus lowering the freezing point.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2016>23","subject":"Physics","year":"2016","type":"Objective","topic":"HEAT ENERGY : EFFECTS OF HEAT ON MATTER","question":"A pressurized perfume bottle is left on the window pane of a room. What happens to the gas molecules of the perfume on a sunny day? They","images":[],"options":{"A":"expand","B":"collide less often","C":"move more rapidly","D":"contract"},"answer":"C","explanation":"When the perfume bottle is left on the window pane on a sunny day, the heat from the sun increases the kinetic energy of the gas molecules in the perfume. This causes the molecules to move more rapidly. This is based on the kinetic theory of gases which states that the temperature of a gas is directly proportional to the average kinetic energy of its molecules.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>24","subject":"Physics","year":"2016","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : SPEED, FREQUENCY AND WAVELENGTH","question":"Given that v, f and \u03bb are the velocity, frequency and wavelength of a wave respectively. Which of the following equation is correct?","images":[],"options":{"A":"v = f2\u03bb","B":"f = v/\u03bb","C":"f = v/\u03bb2","D":"\u03bb = f/v2"},"answer":"B","explanation":"The relationship between the velocity (v), frequency (f), and wavelength (\u03bb) of a wave is given by the equation v = f\u03bb. Therefore, the frequency of the wave can be calculated by rearranging this equation to f = v/\u03bb.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2016>25","subject":"Physics","year":"2016","type":"Objective","topic":"LIGHT WAVES : PLANE MIRROR","question":"Three letters are placed in front of a plane mirror as illustrated in the diagram below. The image formed is illustrated by","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAD0AAAAaCAAAAAAhoAu7AAAAB3RJTUUH5gsKDggcwuJ4BwAAAIdJREFUOI3VlFEOwCAIQ2Hx/lfufrYpagHjkmV8qeEVqUSFbMSxA2/SxexUBPNNhu6URK81U+E0UTRCLh2+h3FNWVaKXlaidGqKaN+N5Vyorz3L5E3EnqvTQ3nkxyTQ29zx1pwvP3alMbM3mvJaG05p45u2gtzRRg7jGQLalQxrZ+LLf+2/9Ak/ohpAZQNrIgAAAABJRU5ErkJggg==","data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAADkAAAAcCAAAAAD+EkjcAAAAB3RJTUUH5gsKDggplFG8JAAAAIBJREFUOI3VlEEOwCAIBNmG/3+ZnjRSXVe9NHKyhIGRNkXYYTyn4C+kpyeYLd/bSR71FKSjtgXJMzKkNbMtemzixm67FpxEru/sqS0momLmSGFpplqQmjl5N05cdDgDh73QaOjvlmVAb1IqI2O1npOTPlukmSFveoP8xF1/sLvIF8DdE0f6HBEcAAAAAElFTkSuQmCC","data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAC0AAAAZCAAAAACAmvj9AAAAB3RJTUUH5gsKDgg6EO/9+gAAAHRJREFUOI3Vk0EOwCAQAqHx/1+mJ9NFMa2XpuVkdETcVQobOnbg39INAEDU0hAAxhldtIlO3CSROsWcZNoQ2Tdq4goRAKp4R2LpXYulpYF7kwUJb9lu6W6c7VsiCfXDnKZ8VjlwX7Eujy2XDQv9SN/5O3v0CVfpFkAK3nAKAAAAAElFTkSuQmCC"],"options":{"A":"","B":"","C":"","D":""},"answer":"C","explanation":"The   image    formed   is illustrated by:","marks":"1","difficulty":"1"},{"id":"objective>Physics>2016>26","subject":"Physics","year":"2016","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : SPEED, FREQUENCY AND WAVELENGTH","question":"The distance between two successive troughs of a wave is 0.4m. If the frequency of the source is 825Hz. Calculate the speed of the wave.","images":[],"options":{"A":"165.0 ms-1","B":"330.0 ms-1","C":"412.5 ms-1","D":"825.0 ms-1"},"answer":"B","explanation":"The distance between two successive troughs of a wave is the wavelength. The speed of a wave is given by the formula speed = frequency * wavelength. Substituting the given values, speed = 825Hz * 0.4m = 330 ms-1. Therefore, the correct option is 2.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2016>27","subject":"Physics","year":"2016","type":"Objective","topic":"ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM","question":"X-rays and infra-red rays are both electromagnetic. Which common property do the waves have? Both waves","images":[],"options":{"A":"are longitudinal","B":"have the same frequency","C":"have the same wavelength","D":"travel at the same speed in a vacuum"},"answer":"D","explanation":"X-rays and infra-red rays are both types of electromagnetic waves. All electromagnetic waves, regardless of their frequency or wavelength, travel at the same speed in a vacuum, which is the speed of light (approximately 3.00 x 10^8 m/s). Therefore, the correct option is 4.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>28","subject":"Physics","year":"2016","type":"Objective","topic":"LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES","question":"The image formed by a concave mirror is real, inverted and magnified, when the object is place","images":[],"options":{"A":"at the focus","B":"at the centre of curvature","C":"beyond the centre of curvature","D":"between the centre of curvature and the focus"},"answer":"D","explanation":"When an object is placed between the center of curvature and the focus the image will be real, inverted and magnified","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>29","subject":"Physics","year":"2016","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"Total internal reflection  I. is a phenomenon of refraction of light  II. occurs when light rays travel into a denser medium   III. occurs when the critical angle is just exceeded   IV. is a phenomenon of reflection of light    Which of the statements above are correct?","images":[],"options":{"A":"I and II only","B":"I and III only","C":"I, II and III only","D":"I, III and IV only"},"answer":"B","explanation":"Total internal reflection is a phenomenon that occurs when light travels from a denser medium to a less dense medium at an angle greater than the critical angle.  hus, the option that includes these correct statements is:  I and III only","marks":"1","difficulty":"3"},{"id":"objective>Physics>2016>30","subject":"Physics","year":"2016","type":"Objective","topic":"LIGHT WAVES : DISPERSION OF WHITE LIGHT","question":"Complementary colours are those which","images":[],"options":{"A":"have the same refractive index","B":"have the same wavelength","C":"add-up to produce black light","D":"add-up to produce white light"},"answer":"D","explanation":"Complementary colors are pairs of colors which, when combined or mixed, cancel each other out (lose hue) by producing a grayscale color like white or black. When placed next to each other, they create the strongest contrast for those two colors. Complementary colors may also be called 'opposite colors'. So, the correct answer is 'add-up to produce white light'.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>31","subject":"Physics","year":"2016","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(\ud835\udecc), PERIOD (T) AND VELOCITY (V)","question":"The diagram above illustrates the waveform of a note produced by vibrations in an air column of length, L. If the speed of sound in air is V, derive an expression for the frequency of the note","images":["data:image/png;base64,"],"options":{"A":"V/L","B":"5VL/2","C":"5L/4V","D":"5V/4L"},"answer":"D","explanation":"l = 5/4 \u03bb  \u03bb=4l5  Recall, V = f\u03bb  f=V\u03bb  f=V4l/5   = 5V/4L","marks":"1","difficulty":"3"},{"id":"objective>Physics>2016>32","subject":"Physics","year":"2016","type":"Objective","topic":"SOUND WAVES : SOURCES OF SOUND","question":"The pair of musical instruments that works on the vibration of air in pipes is","images":[],"options":{"A":"piano and the organ","B":"guitar and the flute","C":"trumpet and the violin","D":"flute and the trumpet"},"answer":"D","explanation":"The flute and the trumpet are both wind instruments that produce sound from the flow of air across an opening; in the flute, the air is directed against the edge of a hole, causing it to vibrate and produce sound, while in the trumpet, the player's lips vibrate to create sound as they blow into a large, flared bell. So, the correct answer is 'flute and the trumpet'.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>33","subject":"Physics","year":"2016","type":"Objective","topic":"LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS","question":"An astronomical telescope has objective and eye-piece lenses of focal lengths 3.5m and 5 cm respectively. Determine the magnifying power of the telescope when in normal adjustment.","images":[],"options":{"A":"70.0","B":"17.5","C":"7.0","D":"0.7"},"answer":"A","explanation":"The magnifying power of a telescope in normal adjustment is given by the ratio of the focal length of the objective lens to the focal length of the eyepiece. In this case, the focal length of the objective lens is 3.5m (or 350cm) and the focal length of the eyepiece is 5cm. Therefore, the magnifying power is 350cm/5cm = 70.0. Hence, option 1 is correct.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2016>34","subject":"Physics","year":"2016","type":"Objective","topic":"ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY","question":"An aluminium cable of diameter 4 \u00d7 10-3m and resistivity 3.0 \u00d7 10-4\u03a9m has a resistance of 21\u03a9. Calculate the length of the cable   (\u03c0 = 3.14)","images":[],"options":{"A":"8.0 \u00d7 102m","B":"8.8 \u00d7 103m","C":"8.0 \u00d7 104m","D":"8.8 \u00d7 104m"},"answer":"B","explanation":"Given; d = 4 \u00d7 10-3m  Resistivity = 3.0 \u00d7 10-8\u03a9m  R = 21\u03a9  \u03c0 = 3.14, l = ?  Recall,R=\u03e0LA  L=AR\u03e0  L=227\u00d716 \u00d7 10-64\u00d7213.0 \u00d7 10-8  L= 8.8 \u00d7 103m","marks":"1","difficulty":"3"},{"id":"objective>Physics>2016>35","subject":"Physics","year":"2016","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC CIRCUIT","question":"The ammeter A2 shown in the circuit diagram above reads 3.0 A. Determine the reading of the ammeter A1","images":["data:image/png;base64,"],"options":{"A":"12A","B":"9A","C":"7A","D":"2A"},"answer":"D","explanation":"V1 = V2  \u2234 I1R1 = I2R2  A1 \u00d7 6\u03a9 = 3.0 \u00d7 4\u03a9  A1=3.0 \u00d7 4\u03a9 6\u03a9=6.03  A1 = 2.0A","marks":"1","difficulty":"3"},{"id":"objective>Physics>2016>36","subject":"Physics","year":"2016","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC ENERGY AND POWER","question":"The electricity meters in houses measure energy units consumed in","images":[],"options":{"A":"kilowatt - hour","B":"volt","C":"ampere","D":"coulomb"},"answer":"A","explanation":"Electricity meters in houses measure the amount of electrical energy consumed. The standard unit of electrical energy is the kilowatt-hour (kWh), which is the amount of energy used by a load of one kilowatt over a period of one hour. Hence, option 1 is correct.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>37","subject":"Physics","year":"2016","type":"Objective","topic":"GRAVITATIONAL FIELD : NEWTON\u2019S LAW OF GRAVITATION","question":"A man and his friend have masses 70kg and 60kg respectively. If they are seated 1.0m apart, calculate the gravitational force of attraction between them.  (G = 6.67 \u00d7 10-11 Nm2kg-2)","images":[],"options":{"A":"1.59 \u00d7 10-14N","B":"2.80 \u00d7 10-7N","C":"1.30 \u00d7 102N","D":"6.30 \u00d7 1013N"},"answer":"B","explanation":"Recall,  From Newton's Gravitational Law;  F=Gm1m2r2  F=6.67 \u00d7 1011 \u00d7 70 \u00d7 60 (1.0)2  F = 2.80 \u00d7 10-7N","marks":"1","difficulty":"3"},{"id":"objective>Physics>2016>38","subject":"Physics","year":"2016","type":"Objective","topic":"ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.","question":"The p.d. across a parallel plate capacitor is 103V. If the distance between the two plates is 10cm, calculate the magnitude of the electric field strength between the plates.","images":[],"options":{"A":"1.0 \u00d7 104 Vm-1","B":"1.0 \u00d7 105 Vm-1","C":"1.5 \u00d7 105 Vm-1","D":"2.0 \u00d7 105 Vm-1"},"answer":"A","explanation":"Recall,ElectricField=P.ddistance  E = 103/0.1    = 1.0 \u00d7 104Vm-1","marks":"1","difficulty":"3"},{"id":"objective>Physics>2016>39","subject":"Physics","year":"2016","type":"Objective","topic":"ELECTRIC FIELD : PRODUCTION OF ELECTRIC CHARGES","question":"Two different materials, rubbed against each other, acquire opposite charges when separated. This is an example of charging by","images":[],"options":{"A":"induction","B":"friction","C":"conduction","D":"convection"},"answer":"B","explanation":"When two different materials are rubbed against each other and acquire opposite charges when separated, this is an example of charging by friction. Charging by friction occurs when electrons are transferred from one material to another through the process of rubbing. Therefore, the correct answer is option 2.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>40","subject":"Physics","year":"2016","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE","question":"Which of the following factors does not affect the e.m.f of a primary cell? Its","images":[],"options":{"A":"size","B":"internal resistance","C":"operating temperature","D":"duration of usage"},"answer":"A","explanation":"The electromotive force (e.m.f) of a primary cell is determined by the chemical reaction within the cell, not its physical size. The other factors listed (internal resistance, operating temperature, and duration of usage) can affect the e.m.f because they can influence the efficiency of the chemical reaction or the flow of electrons.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>41","subject":"Physics","year":"2016","type":"Objective","topic":"MAGNETIC FIELD : MAGNETIZATION AND DEMAGNETIZATION","question":"Two magnets are used to magnetize a soft iron bar PQ as illustrated in the diagram above. The correct polarity at P and Q respectively are","images":["data:image/png;base64,"],"options":{"A":"S and N","B":"N and S","C":"S and S","D":"N and N"},"answer":"B","explanation":"The correct polarity at P and Q respectively are N and S respectively.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>42","subject":"Physics","year":"2016","type":"Objective","topic":"MAGNETIC FIELD : USE OF ELECTROMAGNETS","question":"In strong magnets, keepers are used to","images":[],"options":{"A":"reduce self-demagnetization","B":"cancel the effect of the earth's magnetic field","C":"protect the magnet from stray electric fields","D":"increase the strength of the magnets"},"answer":"A","explanation":"Keepers are used in strong magnets to reduce self-demagnetization. Self-demagnetization is a process where a magnet gradually loses its magnetism over time. This can be caused by the magnet's own magnetic field, which can induce opposing magnetic fields within the magnet itself. By using a keeper, the magnetic field lines are 'short-circuited' and this reduces the effect of self-demagnetization.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>43","subject":"Physics","year":"2016","type":"Objective","topic":"MAGNETIC FIELD : MAGNETIC FORCE ON A MOVING CHARGED PARTICLE","question":"A 10\u03bcC charge moves with a velocity of 1.0 \u00d7 105 ms-1 at right angle of a uniform magnetic field of flux density 5.0 \u00d7 10-4T. Calculate the force on the charge","images":[],"options":{"A":"5.0 \u00d7 10-5N","B":"5.0 \u00d7 10-4N","C":"5.0 \u00d7 105N","D":"`5.0 \u00d7 106N"},"answer":"B","explanation":"Recall, F = qvBsin\u03b8  where, B = 5.0 \u00d7 10-4T  Q = 10\u03bcC  F = ?  F = 5.0 \u00d7 10-4 \u00d7 1.0 \u00d7 105 \u00d7 101 \u00d7 10-6 \u00d7 sin 90    F = 5.0 \u00d7 10-4N","marks":"1","difficulty":"3"},{"id":"objective>Physics>2016>44","subject":"Physics","year":"2016","type":"Objective","topic":"MAGNETIC FIELD : PROPERTIES OF MAGNETS AND MAGNETIC MATERIALS","question":"Which of the following statements is not correct about steel and soft iron?","images":[],"options":{"A":"Steel is more readily magnetized than soft iron","B":"Permanent magnets are usually made of steel","C":"Soft iron is more readily magnetized than steel","D":"Soft iron more readily loses its magnetism than steel"},"answer":"A","explanation":"Steel is harder to magnetize than soft iron. This is because steel is a permanent magnet, which means it retains its magnetism once it's magnetized. Soft iron, on the other hand, is a temporary magnet, which means it's easy to magnetize and demagnetize. Therefore, the statement 'Steel is more readily magnetized than soft iron' is incorrect.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>45","subject":"Physics","year":"2016","type":"Objective","topic":"MAGNETIC FIELD : USE OF ELECTROMAGNETS","question":"What determines the polarity at the ends of an electromagnet? The","images":[],"options":{"A":"magnitude of the current passing through the wire","B":"material of the core of the magnet","C":"material of the coil","D":"direction of current in the wire"},"answer":"D","explanation":"The polarity of an electromagnet is determined by the direction of the current flowing through the wire. This is based on the right-hand rule, which states that if you point your thumb in the direction of the current, your fingers will curl in the direction of the magnetic field. Therefore, if you reverse the direction of the current, you also reverse the polarity of the electromagnet.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>46","subject":"Physics","year":"2016","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"How many beta particle(s) are emitted in the radioactive decay of   19879 Au \u2192 19880Hg?","images":[],"options":{"A":"1","B":"2","C":"3","D":"5"},"answer":"A","explanation":"In the radioactive decay of 19879 Au \u2192 19880Hg, one beta particle is emitted. This is because a beta decay involves the transformation of a neutron into a proton and an electron (the beta particle). The atomic number (the bottom number) increases by one, indicating that one proton has been added to the nucleus. Therefore, only one beta particle is emitted.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>47","subject":"Physics","year":"2016","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : FUSION AND FISSION","question":"The phenomenon by which two light atomic nuclei combine to form a heavy nuclide with the release of energy is known as","images":[],"options":{"A":"radioactivity","B":"nuclear fusion","C":"nuclear fission","D":"chain reaction"},"answer":"B","explanation":"Nuclear fusion is the phenomenon whereby two light atomic nuclei combine to form a heavy nuclide with the release of energy.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2016>48","subject":"Physics","year":"2016","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"Which of the following graphs is correct for the decay of a radioactive substance with a half-life of 2 years?","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"C","explanation":"The graph that is correct for the decay of a radioactive substance with a half-life of 2 years is:","marks":"1","difficulty":"3"},{"id":"objective>Physics>2016>49","subject":"Physics","year":"2016","type":"Objective","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"In a p-type semiconductor, the","images":[],"options":{"A":"number of holes are equal to the number of electrons","B":"electrical resistivity increases","C":"electrons are the majority charge carriers","D":"holes are the majority charge carriers"},"answer":"D","explanation":"In a p-type semiconductor, holes are the majority charge carriers. A p-type semiconductor is created by doping an intrinsic semiconductor with an electron acceptor element during manufacture. The majority charge carriers are holes, while the minority charge carriers are electrons.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2016>50","subject":"Physics","year":"2016","type":"Objective","topic":"WAVE-PARTICLE PARADOX : DUALITY OF MATTER","question":"Let \u0394 x be the uncertainty in the measurement of position and \u0394p the uncertainty in measurement of momentum. Then, the uncertainty principle relation is given as","images":[],"options":{"A":"\u0394 x. \u0394p = h","B":"\u0394x. \u0394p \u2264 h","C":"\u0394x. \u0394p \u2265 h","D":"\u0394x. \u0394p > h"},"answer":"C","explanation":"The uncertainty principle relation is given as:    \u0394x \u00b7 \u0394p \u2265 h    This relation states that the product of the uncertainties in position (\u0394x) and momentum (\u0394p) is greater than or equal to Planck's constant (h).","marks":"1","difficulty":"3"}];